// Parse and validate incoming chat request
const body = $input.item.json.body || $input.item.json;
const userMessage = body.message || body.query || body.question || '';
const sessionId = body.sessionId || `session_${Date.now()}`;
const chatHistory = body.history || [];

if (!userMessage.trim()) {
  throw new Error('No message provided in request body. Expected: { "message": "your question" }');
}

// Build Gemini embedding body string
const geminiBodyString = JSON.stringify({
  model: "models/gemini-embedding-001",
  content: {
    parts: [{ text: userMessage.trim() }]
  },
  taskType: "RETRIEVAL_QUERY"
});

return [{
  json: {
    userMessage: userMessage.trim(),
    sessionId,
    chatHistory,
    timestamp: new Date().toISOString(),
    geminiBodyString
  }
}];

const pineconeResult = $input.item.json;
const userMessage = $('Parse & Validate Input').item.json.userMessage;
const chatHistory = $('Parse & Validate Input').item.json.chatHistory;
const sessionId = $('Parse & Validate Input').item.json.sessionId;
const matches = pineconeResult.matches || [];

// Filter by relevance score threshold
const relevantMatches = matches.filter(m => m.score > 0.35);

if (relevantMatches.length === 0) {
  return [{
    json: {
      userMessage,
      sessionId,
      chatHistory,
      retrievedContext: '',
      hasContext: false,
      sources: []
    }
  }];
}

// Build context block
const contextBlocks = relevantMatches.map((match, i) => {
  const meta = match.metadata || {};
  return `[Chunk ${i+1} | Score: ${match.score.toFixed(3)} | Source: ${meta.fileName || 'unknown'}]\n${meta.text || ''}`;
}).join('\n\n---\n\n');

const sources = [...new Set(relevantMatches.map(m => m.metadata?.fileName || 'unknown'))];

// Format chat history (last 6 turns)
const historyText = chatHistory.slice(-6).map(turn => 
  `${turn.role === 'user' ? 'Usuario' : 'Asistente'}: ${turn.content}`
).join('\n');

return [{
  json: {
    userMessage,
    sessionId,
    chatHistory,
    retrievedContext: contextBlocks,
    historyText,
    hasContext: true,
    sources,
    matchCount: relevantMatches.length
  }
}];

// Build the final prompt for the LLM
const { userMessage, retrievedContext, historyText, hasContext } = $input.item.json;

const systemPrompt = `Eres el Asistente de Conocimiento de AIO Strategy, una consultora de AI y datos B2B con sede en Querétaro, México, especializada en manufactura, agroindustria y logística en la región Bajío.

Tu función:
- Responder preguntas sobre documentos, propuestas y casos de uso de AIO Strategy
- Proporcionar información precisa basada ÚNICAMENTE en el contexto recuperado
- Si no encuentras la información en el contexto, indicarlo claramente
- Responder siempre en español, con tono profesional y consultivo
- Citar las fuentes cuando sea relevante

Reglas importantes:
1. NUNCA inventes información que no esté en el contexto
2. Si la pregunta está fuera del alcance de los documentos indexados, di: "No encontré información sobre eso en la base de conocimiento de AIO Strategy"
3. Sé conciso pero completo. Máximo 400 palabras salvo que se pida un análisis detallado
4. Cuando hay contexto suficiente, ofrece insights accionables`;

let userPrompt;
if (hasContext) {
  userPrompt = `CONTEXTO RECUPERADO DE LA BASE DE CONOCIMIENTO:\n${retrievedContext}\n\n`;
  if (historyText) {
    userPrompt += `HISTORIAL DE CONVERSACIÓN:\n${historyText}\n\n`;
  }
  userPrompt += `PREGUNTA ACTUAL DEL USUARIO:\n${userMessage}`;
} else {
  userPrompt = `No se encontró contexto relevante en la base de conocimiento para esta consulta.\n\n`;
  if (historyText) {
    userPrompt += `HISTORIAL:\n${historyText}\n\n`;
  }
  userPrompt += `PREGUNTA: ${userMessage}\n\nResponde indicando que no hay información disponible sobre ese tema en la base de conocimiento de AIO Strategy.`;
}

const geminiBodyString = JSON.stringify({
  system_instruction: {
    parts: [{ text: systemPrompt }]
  },
  contents: [
    {
      role: "user",
      parts: [{ text: userPrompt }]
    }
  ],
  generationConfig: {
    temperature: 0.3,
    maxOutputTokens: 800
  }
});

return [{
  json: {
    ...$input.item.json,
    systemPrompt,
    userPrompt,
    geminiBodyString
  }
}];

// Package the final response
const llmResult = $input.item.json;
const contextData = $('Build RAG Context').item.json;

// Gemini response structure: candidates[0].content.parts[0].text
const assistantMessage = llmResult.candidates?.[0]?.content?.parts?.[0]?.text 
  || 'Error al generar respuesta';

// Update chat history
const updatedHistory = [
  ...contextData.chatHistory,
  { role: 'user', content: contextData.userMessage },
  { role: 'assistant', content: assistantMessage }
];

// Keep history manageable (last 20 turns)
const trimmedHistory = updatedHistory.slice(-20);

return [{
  json: {
    response: assistantMessage,
    sources: contextData.sources || [],
    matchCount: contextData.matchCount || 0,
    sessionId: contextData.sessionId,
    history: trimmedHistory,
    metadata: {
      model: 'gemini-2.5-flash',
      embeddingModel: 'gemini-embedding-001',
      hasContext: contextData.hasContext,
      timestamp: new Date().toISOString()
    }
  }
}];

const embedding = $json.embedding.values;
const userMessage = $('Parse & Validate Input').item.json.userMessage;
const chatHistory = $('Parse & Validate Input').item.json.chatHistory;
const sessionId = $('Parse & Validate Input').item.json.sessionId;

const pineconeBodyString = JSON.stringify({
  vector: embedding,
  topK: 5,
  includeMetadata: true,
  namespace: "aio-strategy-docs"
});

return [{ 
  json: { 
    embedding, 
    userMessage, 
    chatHistory, 
    sessionId, 
    pineconeBodyString 
  } 
}];
